export class DeviceComponent {

  @Input() device: any;

  getDeviceType(): string {

    const cat = String(this.device?.category || '').toLowerCase();

    if (cat.includes('pc')) return 'pc';
    if (cat.includes('switch')) return 'switch';
    if (cat.includes('router')) return 'router';
